import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { FiXCircle } from 'react-icons/fi'; // Icon pentru închidere

import WordIcon from '../assets/icons_sidebar/word.png';
import ExcelIcon from '../assets/icons_sidebar/excel.png';
import PowerPointIcon from '../assets/icons_sidebar/office.png';
import PdfIcon from '../assets/icons_sidebar/acrobat.png';
import '../assets/styles/Sidebar.css';

const Sidebar = () => {
  const [openWordFiles, setOpenWordFiles] = useState([]);
  const [openExcelFiles, setOpenExcelFiles] = useState([]);
  const [openPptFiles, setOpenPptFiles] = useState([]);
  const [openPdfFiles, setOpenPdfFiles] = useState([]);
  const navigate = useNavigate();

  const handleFileOpen = (fileName, ext, filePath) => {
    if (['doc', 'docx'].includes(ext)) {
      setOpenWordFiles(prev => [...prev, { name: fileName, path: filePath }]);
    } else if (['xls', 'xlsx'].includes(ext)) {
      setOpenExcelFiles(prev => [...prev, { name: fileName, path: filePath }]);
    } else if (['ppt', 'pptx'].includes(ext)) {
      setOpenPptFiles(prev => [...prev, { name: fileName, path: filePath }]);
    } else if (ext === 'pdf') {
      setOpenPdfFiles(prev => [...prev, { name: fileName, path: filePath }]);
    }
  };

  const handleOpenFileFromSidebar = (filePath, type) => {
    fetch(`/shortcuts/file-explorer/server-action/?filePath=${encodeURIComponent(filePath)}`, { method: 'POST' })
      .then(response => {
        if (response.ok) {
          navigate(`/shortcuts/${type}`);
        } else {
          console.error('Failed to open the file:', response.statusText);
        }
      })
      .catch(error => console.error('Error:', error));
  };

  const handleCloseFile = (filePath, setOpenFiles) => {
    setOpenFiles(prev => prev.filter(file => file.path !== filePath));
  };

  const renderOpenFilesList = (openFiles, type, setOpenFiles) => (
    <ul className="open-files-list">
      {openFiles.map((file, index) => (
        <li key={index} className="file-item">
          <span onClick={() => handleOpenFileFromSidebar(file.path, type)}>
            {file.name}
          </span>
          <FiXCircle 
            className="close-icon" 
            onClick={() => handleCloseFile(file.path, setOpenFiles)} 
          />
        </li>
      ))}
    </ul>
  );

  return (
    <div className="sidebar">
      <Link to="/shortcuts/word" className="sidebar-button">
        <img src={WordIcon} alt="Microsoft Word" className="icon" />
        Microsoft Word
        {openWordFiles.length > 0 && renderOpenFilesList(openWordFiles, 'word', setOpenWordFiles)}
      </Link>

      <Link to="/shortcuts/excel" className="sidebar-button">
        <img src={ExcelIcon} alt="Microsoft Excel" className="icon" />
        Microsoft Excel
        {openExcelFiles.length > 0 && renderOpenFilesList(openExcelFiles, 'excel', setOpenExcelFiles)}
      </Link>

      <Link to="/shortcuts/powerpoint" className="sidebar-button">
        <img src={PowerPointIcon} alt="PowerPoint" className="icon" />
        PowerPoint
        {openPptFiles.length > 0 && renderOpenFilesList(openPptFiles, 'powerpoint', setOpenPptFiles)}
      </Link>

      <Link to="/shortcuts/pdf" className="sidebar-button">
        <img src={PdfIcon} alt="PDF Reader" className="icon" />
        PDF Reader
        {openPdfFiles.length > 0 && renderOpenFilesList(openPdfFiles, 'pdf', setOpenPdfFiles)}
      </Link>
    </div>
  );
};

export default Sidebar;
